### Knex.js Query Builder

Knex is a SQL query builder supporting PostgreSQL, MySQL, SQLite, and more.

```bash
npm install knex pg
```

```javascript
const db = require('knex')({
  client: 'pg',
  connection: {
    host: 'localhost',
    database: 'myapp',
    user: 'postgres',
    password: 'password'
  }
});

// Query
const users = await db('users').where({ active: true }).select('*');
const user = await db('users').where({ id: 1 }).first();
await db('users').insert({ name: 'John', email: 'john@test.com' });
await db('users').where({ id: 1 }).update({ name: 'Jane' });
await db('users').where({ id: 1 }).del();
```

### PostgreSQL with pg

```javascript
const { Pool } = require('pg');
const pool = new Pool({
  connectionString: process.env.DATABASE_URL
});

app.get('/users', async (req, res) => {
  const result = await pool.query('SELECT * FROM users');
  res.json(result.rows);
});
```

### Sequelize ORM

A full-featured ORM for SQL databases:

```javascript
const { Sequelize, DataTypes } = require('sequelize');
const sequelize = new Sequelize(process.env.DATABASE_URL);

const User = sequelize.define('User', {
  name: { type: DataTypes.STRING, allowNull: false },
  email: { type: DataTypes.STRING, unique: true }
});

await User.sync();
const users = await User.findAll();
const user = await User.findByPk(1);
```

### Connection Pooling

Connection pools improve performance by reusing connections:

```javascript
const pool = new Pool({ max: 20, idleTimeoutMillis: 30000 });
```

codeExample:
const knex = require('knex');
const db = knex({
  client: 'pg',
  connection: { connectionString: process.env.DATABASE_URL },
  pool: { min: 2, max: 10 }
});

app.get('/api/users', async (req, res) => {
  const users = await db('users').orderBy('created_at', 'desc');
  res.json({ data: users });
});
